        let buggyTasksRunning = false;

        const buggyProgressBar = document.getElementById('buggyProgressBar');
        const buggyProgressLabel = document.getElementById('buggyProgressLabel');
        const startBuggyButton = document.getElementById('startBuggy');

        function updateBuggyProgressBar() {
            const clampedProgress = Math.min(100, Math.max(0, buggyProgressPercentage));
