            if (buggyProgressPercentage > 100) {
                buggyProgressBar.style.backgroundColor = '#dc3545'; // Red
                buggyProgressLabel.style.color = '#dc3545';
            } else if (buggyProgressPercentage < 100 && buggyProgressPercentage > 0) {
                 buggyProgressBar.style.backgroundColor = '#4CAF50'; // Green
                 buggyProgressLabel.style.color = '#333';
            } else {
                buggyProgressBar.style.backgroundColor = '#e0e0e0'; // Grey when 0 or finished
                buggyProgressLabel.style.color = '#333';
            }
        }

        function buggyTask(amount) {
            return new Promise(resolve => {
                const delay = Math.random() * 200 + 50; // Simulate varying task durations
                setTimeout(() => {
                    // !!! THE BUG: Shared state modification without synchronization !!!
                    // Multiple tasks read buggyProgressPercentage, modify it, and write it back
                    // This leads to race conditions.
                    buggyProgressPercentage = buggyProgressPercentage + amount;
                    updateBuggyProgressBar();
                    console.log(`Buggy Task finished. Current progress: ${buggyProgressPercentage.toFixed(2)}%`);
                    resolve();
                }, delay);
            });
        }

        async function startBuggyTasks() {
            if (buggyTasksRunning) return;
            buggyTasksRunning = true;
            startBuggyButton.disabled = true;
            buggyProgressPercentage = 0; // Reset for a new run
            updateBuggyProgressBar();

            const tasks = [];
            for (let i = 0; i < BUGGY_TOTAL_TASKS; i++) {
                tasks.push(buggyTask(BUGGY_INCREMENT_PER_TASK));
            }
            await Promise.all(tasks); // Launch all tasks concurrently

            buggyTasksRunning = false;
            startBuggyButton.disabled = false;
            console.log(`Buggy: All tasks completed. Final percentage: ${buggyProgressPercentage.toFixed(2)}%`);
