                correctedProgressLabel.style.color = '#333';
            }
        }

        function correctedTask(amount) {
            return new Promise(resolve => {
                const delay = Math.random() * 200 + 50;
                setTimeout(() => {
                    // !!! THE FIX: Update operation is now part of a serialized chain !!!
                    // The actual state modification happens here, but the *invocation*
                    // of this task is controlled by the promise chain in startCorrectedTasks().
                    correctedProgressPercentage = correctedProgressPercentage + amount;
                    updateCorrectedProgressBar();
                    console.log(`Corrected Task finished. Current progress: ${correctedProgressPercentage.toFixed(2)}%`);
                    resolve();
                }, delay);
            });
        }

