            if (correctedTasksRunning) return;
            correctedTasksRunning = true;
            startCorrectedButton.disabled = true;
            correctedProgressPercentage = 0; // Reset
            updateCorrectedProgressBar();

            let promiseChain = Promise.resolve(); // Start with an immediately resolved promise

            for (let i = 0; i < CORRECTED_TOTAL_TASKS; i++) {
                // Each new task waits for the previous one in the chain to complete
                // before it starts its own execution and updates the shared state.
                promiseChain = promiseChain.then(() => correctedTask(CORRECTED_INCREMENT_PER_TASK));
            }

            await promiseChain; // Wait for the entire chain to complete

            correctedTasksRunning = false;
            startCorrectedButton.disabled = false;
            console.log(`Corrected: All tasks completed. Final percentage: ${correctedProgressPercentage.toFixed(2)}%`);
        }

        function resetCorrectedTasks() {
            correctedProgressPercentage = 0;
            updateCorrectedProgressBar();
            startCorrectedButton.disabled = false;
            correctedTasksRunning = false;
        }

        // Initial update on load
        updateBuggyProgressBar();
        updateCorrectedProgressBar();
    </script>
